INSERT INTO `t_change_log` VALUES (1,'v3.2.0',1,'技术部 - 张明远','2026-03-08','1. 完成司机管理、货主管理、订单管理全模块架构重构，优化系统性能，页面加载速度提升 50%\n2. 新增洛阳区域物流路线智能规划功能，支持多站点装货 / 卸货自动排程\n3. 上线司机结算自动化模块，支持批量对账、一键打款，财务效率提升 80%\n4. 优化集装箱运输订单全流程跟踪，新增 GPS 实时定位、电子围栏预警功能\n5. 适配新版道路运输从业资格证电子证照核验接口，合规性升级',NULL,'2026-03-25 16:03:49','2026-03-25 16:03:49'),(2,'v3.2.1',2,'产品部 - 李雨桐','2026-03-20','1. 优化装货 / 卸货凭证上传模块',NULL,'2026-03-25 16:05:11','2026-03-25 16:05:11'),(3,'v3.2.2',3,'测试部 - 王浩','2026-03-22','1. 修复司机档案身份证号校验规则错误问题\n2. 修复装货订单磅重计算逻辑错误，解决净重与毛重、皮重不匹配的问题\n3. 修复货主开票信息批量导出时，银行账号显示不全的 Bug\n4. 修复运输订单路线定位异常问题，修正洛阳孟津区部分地址经纬度偏差\n5. 修复司机结算模块，部分外协司机应付运价计算错误的问题\n6. 优化系统登录稳定性，修复部分用户登录闪退的问题',NULL,'2026-03-25 16:06:07','2026-03-25 16:06:07');
/*!40000 ALTER TABLE `t_change_log` ENABLE KEYS */;
UNLOCK TABLES;

