CREATE TABLE `t_maintenance` (
  `maintenance_id` bigint NOT NULL AUTO_INCREMENT COMMENT '车辆保养表ID',
  `vehicle_id` bigint NOT NULL COMMENT '车辆ID',
  `enterprise_id` bigint DEFAULT NULL COMMENT '企业ID',
  `maintenance_person` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '保养人',
