--
-- Table structure for table `t_msg`
--

DROP TABLE IF EXISTS `t_msg`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `t_msg` (
  `msg_id` bigint NOT NULL AUTO_INCREMENT COMMENT '消息id',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `msg_type` smallint NOT NULL COMMENT '消息类型',
  `msg_sub_type` smallint NOT NULL COMMENT '消息子类型',
  `receiver_type` tinyint NOT NULL COMMENT '接收者类型 1后管 2货主 3司机',
  `receiver_id` bigint NOT NULL COMMENT '接收者id',
  `data_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '相关数据id',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '标题',
  `content` varchar(3000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '内容',
  `read_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已读',
  `read_time` datetime DEFAULT NULL COMMENT '已读时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`msg_id`) USING BTREE,
  KEY `idx_msg` (`msg_type`,`msg_sub_type`,`receiver_type`,`receiver_id`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=11390 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='通知消息 数据表 by listen 2022年7月24日 21:07';
