INSERT INTO `t_oa_enterprise` VALUES (1,'春风物流有限公司',NULL,'platform.tms.1024lab.net',1,2,'LZWL','91410029222124324',NULL,'张玲玲','15222222222','382279036@qq.com','410000','河南省','410300','洛阳市','410305','涧西区','洛阳市涧西区建设路182号107室',NULL,'春风物流','春风物流TMS','<p style=\"line-height: 1.5;\"><span style=\"font-size: 14px;\"> &nbsp; &nbsp; &nbsp;</span><span style=\"font-size: 14px; font-family: 仿宋;\"> </span> 量子物流有限公司成立于2009年5月份，总部经营地址位于平顶山市叶县叶舞路长途汽车站西300米路北，注册资金1500万元。</p><p style=\"line-height: 1.5;\">公司2015年被评为“道路运输企业质量信誉等级AA”；2016年被连续评为“先进单位”；2017年在郑州成立分公司。公司具有多年货运车辆挂靠、普通货</p><p style=\"line-height: 1.5;\">cd物运输、普通集装箱及冷藏箱专业运输、大件货物运输能力及金融贷款能力。现公司拥有众多重型半挂牵引车、重型仓栏运输车、特种结构运输车、小</p><p style=\"line-height: 1.5;\">箱货运输车等车辆。</p>','备案号',0,0,1,'管理员','2022-09-07 14:50:30','2026-03-26 03:00:52'),(2,'智运物流',NULL,'lab.tms.1024lab.net,localhost:60001',0,1,NULL,'4029222124324',NULL,'1024lab','13700000001',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'智运','智运TMS','','',0,0,1,'管理员','2026-03-25 16:39:01','2026-03-28 03:21:36');
