--
-- Table structure for table `t_order`
--

DROP TABLE IF EXISTS `t_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `t_order` (
  `order_id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `order_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '订单编号',
  `shipper_id` bigint NOT NULL COMMENT '货主ID',
  `enterprise_id` bigint NOT NULL COMMENT '企业ID',
  `nft_enterprise_id` bigint DEFAULT NULL COMMENT '网络货运平台高公司',
  `order_type` int NOT NULL DEFAULT '0' COMMENT '订单类型',
  `split_transport_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否分段运输',
  `schedule_id` bigint NOT NULL COMMENT '调度员',
  `area_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '所属区域',
  `business_type_code` int NOT NULL COMMENT '运输类型',
  `container_business_type_id` bigint DEFAULT NULL COMMENT '业务类型',
  `cabinet_id` bigint DEFAULT NULL COMMENT '柜型',
  `distance` bigint DEFAULT NULL COMMENT '距离',
  `status` int NOT NULL COMMENT '状态',
  `container_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '提箱地点',
  `placing_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '装货地点',
  `unloading_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '卸货地点',
  `return_container_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '还箱地点',
  `transport_route_id` bigint DEFAULT NULL COMMENT '运输路线ID',
  `single_trip_receive_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '单趟应收金额',
  `single_trip_freight_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '单趟应付金额',
  `schedule_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分配状态',
  `tax_point` int NOT NULL DEFAULT '0' COMMENT '税点',
  `load_time` datetime DEFAULT NULL COMMENT '装货时间',
  `unload_time` datetime DEFAULT NULL COMMENT '卸货时间',
  `latest_packing_time` datetime DEFAULT NULL COMMENT '最迟装货时间',
  `remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `shipper_contact` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '客户联系人',
  `shipper_order_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '客户订单号',
  `manager_id` bigint DEFAULT NULL COMMENT '业务负责人',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '创建人名称',
  `update_user_id` bigint DEFAULT NULL COMMENT '更新人ID',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`order_id`) USING BTREE,
  KEY `idx_shipper_id` (`shipper_id`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE,
  KEY `idx_schedule_id` (`schedule_id`) USING BTREE,
  KEY `idx_business_type_code` (`business_type_code`) USING BTREE,
  KEY `idx_container_business_type_id` (`container_business_type_id`) USING BTREE,
  KEY `idx_cabinet_id` (`cabinet_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=26 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

