INSERT INTO `t_system_config` VALUES (1,'万能密码','super_password','789321','789321','2026-03-26 02:59:53','2021-12-16 23:32:46'),(2,'本地上传url前缀','local_upload_url_prefix','http://localhost/file/',NULL,'2022-05-20 23:28:38','2022-03-22 13:36:01'),(3,'证件到期-提醒时间设置','expired_certificate_expire_reminder_time','{\"typeList\":[{\"days\":1,\"type\":1},{\"days\":2,\"type\":2},{\"days\":3,\"type\":3},{\"days\":1,\"type\":4},{\"days\":3,\"type\":5},{\"days\":3,\"type\":6},{\"days\":3,\"type\":7},{\"days\":3,\"type\":8},{\"days\":4,\"type\":9},{\"days\":3,\"type\":10},{\"days\":22,\"type\":11}],\"updateName\":\"豆妹\",\"updateTime\":\"2022-08-19T11:19:54.237\"}','更新人：管理员','2022-08-19 11:19:54','2022-07-01 15:20:07'),(4,'销售角色编码','sales_role_code','sales_role',NULL,'2026-02-27 15:12:18','2022-07-07 15:42:14'),(5,'客服角色编码','customer_service_role_code','customer_role',NULL,'2026-02-27 15:12:25','2022-07-07 15:42:38'),(6,'调度角色编码','schedule_role_code','schedule_role',NULL,'2026-02-27 15:12:31','2022-07-07 15:42:38'),(10,'司机端默认用户名','default_driver_name','TMS',NULL,'2026-03-26 03:00:07','2023-08-12 10:17:26'),(11,'隐私协议','privacy_agreement','隐私协议','','2026-03-26 02:59:27','2023-08-27 20:24:19'),(12,'用户协议','user_agreement','用户协议','','2026-03-26 03:41:46','2023-08-27 20:24:39'),(13,'客服电话','customer_service_telephone_numbers','0375-7777777','','2026-03-26 02:59:42','2023-08-27 20:25:33'),(14,'IOS审核配置','iso_audit_config','{\"auditSwitch\": false,\"version\": \"1.0.0\" }','','2023-08-31 09:43:12','2023-08-31 09:42:06'),(15,'安卓审核配置','android_audit_flag','{\"auditSwitch\": false,\"version\": \"1.0.0\" }','','2023-08-31 09:43:22','2023-08-31 09:42:24'),(23,'自有车维修费用分类ID','car_cost_maintenance_category_id','14','','2024-05-20 09:10:56','2024-05-20 09:07:13'),(24,'自有车其他费用分类ID','car_cost_other_category_id','1','','2024-05-20 09:11:02','2024-05-20 09:07:29'),(25,'自有车尿素费用分类ID','car_cost_urea_category_id','12','','2024-05-20 09:11:25','2024-05-20 09:07:41'),(26,'APP端是否展示订单','app_show_order','true','','2024-09-13 09:57:01','2024-08-20 09:21:27'),(27,'APP端是否显示运单','app_show_waybill','true','','2024-09-13 09:56:59','2024-08-20 09:21:47'),(28,'强制修改密码标识','force_edit_pwd_flag','true','强制修改：true\n不强制修改： false','2024-09-13 09:56:21','2024-08-20 10:29:31'),(29,'强制修改密码天数','force_edit_pwd_days','7','','2024-09-13 09:56:24','2024-08-20 10:30:37'),(30,'财务角色编码','finance_role_code','finance_role',NULL,'2025-05-14 09:41:25','2022-07-07 15:42:14'),(31,'统计角色编码','summary_role_code','summary_role',NULL,'2025-05-14 09:41:25','2022-07-07 15:42:14'),(32,'人事角色编码','hr_role_code','hr_role',NULL,'2025-05-14 09:41:25','2022-07-07 15:42:14'),(35,'禁运物品说明','embargo_statement','<div class=\"detCont\">       <div class=\"detBox clearfix\">         <div class=\"detFl\">           <div style=\"background: #fff;margin-bottom: 20px;\"><h1             style=\"font-size: 30px;font-weight: normal;line-height: 1.46;margin-bottom: 30px;text-align: center\">禁限物品运输说明</h1>             <div class=\"artCont\" style=\"font-size: 16px;line-height: 1.8;word-break: break-all;\"><p>               <p>为了切实提升运输安全管理，保障人民生命财产安全，不支持运输下列货物：</p>               <p>1、现钞，秒票、人民币、钱。</p>               <p>2、各类武器、弹药、手枪、枪支、子弹、炮弹、手榴弹、地雷、炸弹等。</p>               <p>3、各类易爆炸性物品。如雷管、炸药、火药、鞭炮等。</p>               <p>4、各类易燃烧性物品，包括液体、气体和固体。如汽油、煤油、桐油、酒精、生漆、柴油、气雾剂、气体打火机、瓦斯气瓶、磷、硫磺、火柴等。</p>               <p>5、各类易腐蚀性物品，如火硫酸、盐酸、硝酸、有机溶剂、农药、双氧水、危险化学品等。</p>               <p>6、各类放射性元素及容器，如钴、钚，钋、氡、钫、镭、锕、钍、镤、铀等。</p>               <p>7、各类烈性毒药，如铊、砷、三氧化砷、氧化亚砷、白砷、灰砷、金属砷，砒霜，氰化物，钾氰化物，钠氰化物、氢氰化物等。</p>               <p>8、各类麻醉药物，如鸦片(包括罂粟壳、花、苞、叶)吗啡、可卡因、海洛因、大麻、冰毒、麻黄素及其它制品等。</p>               <p>9、各类生化制品和传染性物品，如炭疽、危险性病菌、毒气、毒素、医药用废弃物等。</p>               <p>10、各种危害国家安全和社会政治稳定以及淫秽出版物、宣传片、印刷品</p>               <p>11、各种妨害公共卫生的物品，如尸骨、动物器官、肢体、未经硝制的的兽皮、未经药制的兽骨等</p>               <p>12.国家法律、法规、行政规章命令禁止流通、进出境物品。如国家秘密文件和资料、国家货币及伪造货币和有价证券、仿真武器、濒危野生动物及其仿制品等。</p>               <p>13、其他国家法律法规禁止运输的，在运输、装卸和贮存保管过程中容易造成人身伤亡和财产损毁而需要特别防护的货物。</p>                <p>对于国家法律法规禁止以上限制运输的物品，平台作为网络货运人无法进行运输，托运人不应提交相关订单。因托运人故意隐瞒运输货物的性质而造成损失，托运人需要承担一切经济和法律后果。</p>             </div>           </div>         </div>       </div>     </div>','','2025-11-05 14:51:30','2025-11-05 14:41:58');
/*!40000 ALTER TABLE `t_system_config` ENABLE KEYS */;
UNLOCK TABLES;

