  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`waybill_voucher_id`) USING BTREE,
  UNIQUE KEY `uk_type_waybill` (`waybill_id`,`type`) USING BTREE,
  KEY `idx_waybill_id` (`waybill_id`) USING BTREE
